def decode_string(s: str) -> str:
    stack, num, res = [], 0, ''
    for char in s:
        if char.isdigit():
            num = num * 10 + int(char)
        elif char == '[':
            stack.append((res, num))
            res, num = '', 0
        elif char == ']':
            prev_res, prev_num = stack.pop()
            res = prev_res + prev_num * res
        else:
            res += char
    return res
